//! Golden tests for N2C query result CBOR encoding.
//!
//! Each test constructs a QueryResult with known synthetic data, encodes it
//! via `encode_query_result`, and compares the output against a binary fixture
//! file in `tests/golden/n2c/`. This validates that our CBOR encoding is
//! deterministic and structurally correct.
//!
//! The fixture files were generated by running these tests with
//! `GOLDEN_UPDATE=1` to write the encoded bytes, then frozen as reference.

use torsten_network::encode_query_result;
use torsten_network::query_handler::{
    DRepSnapshot, GovStateSnapshot, NonMyopicRewardEntry, PoolParamsSnapshot, PoolRewardInfo,
    ProtocolParamsSnapshot, QueryResult, RelaySnapshot, StakePoolSnapshot,
};

/// Strip the MsgResult `[4, ...]` wrapper and HFC `[1, ...]` wrapper,
/// returning just the result payload for structural validation.
fn strip_msg_and_hfc(encoded: &[u8]) -> &[u8] {
    // MsgResult: 82 04 ... = array(2) [4, payload]
    // For BlockQuery results, payload is: 81 <result> = array(1) [result]
    // So header is: 82 04 81 = 3 bytes
    assert_eq!(encoded[0], 0x82, "expected array(2)");
    assert_eq!(encoded[1], 0x04, "expected MsgResult tag 4");
    assert_eq!(encoded[2], 0x81, "expected HFC success array(1)");
    &encoded[3..]
}

/// Helper: decode a minicbor value from bytes and return the decoder
fn decoder(data: &[u8]) -> minicbor::Decoder<'_> {
    minicbor::Decoder::new(data)
}

// ---------------------------------------------------------------------------
// Fixture helpers
// ---------------------------------------------------------------------------

fn fixture_path(name: &str) -> std::path::PathBuf {
    let mut p = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    p.push("n2c");
    p.push(name);
    p
}

/// Load or update a fixture file. When GOLDEN_UPDATE=1 is set, writes the
/// encoded bytes to the fixture path so they can be committed.
fn assert_fixture(name: &str, encoded: &[u8]) {
    let path = fixture_path(name);
    if std::env::var("GOLDEN_UPDATE").is_ok() {
        std::fs::write(&path, encoded).expect("failed to write fixture");
    }
    let expected = std::fs::read(&path).unwrap_or_else(|_| {
        panic!(
            "fixture file not found: {:?}. Run with GOLDEN_UPDATE=1 to generate.",
            path
        )
    });
    assert_eq!(
        encoded,
        &expected[..],
        "CBOR mismatch for fixture {name} (len got={}, expected={})",
        encoded.len(),
        expected.len()
    );
}

// ===========================================================================
// Test 1: GetNonMyopicMemberRewards (tag 2)
// ===========================================================================

fn make_non_myopic_rewards() -> QueryResult {
    QueryResult::NonMyopicMemberRewards(vec![
        NonMyopicRewardEntry {
            stake_amount: 1_000_000_000,
            pool_rewards: vec![(vec![0xAA; 28], 50_000), (vec![0xBB; 28], 75_000)],
        },
        NonMyopicRewardEntry {
            stake_amount: 5_000_000_000,
            pool_rewards: vec![(vec![0xCC; 28], 250_000)],
        },
    ])
}

#[test]
fn test_non_myopic_member_rewards_fixture() {
    let result = make_non_myopic_rewards();
    let encoded = encode_query_result(&result);
    assert_fixture("Result_Conway_NonMyopicMemberRewards", &encoded);
}

#[test]
fn test_non_myopic_member_rewards_structure() {
    let result = make_non_myopic_rewards();
    let encoded = encode_query_result(&result);
    let payload = strip_msg_and_hfc(&encoded);
    let mut dec = decoder(payload);

    // Outer map: stake_amount -> pool_rewards_map
    let map_len = dec.map().unwrap().unwrap();
    assert_eq!(map_len, 2, "expected 2 stake amount entries");

    // Entry 1: stake=1_000_000_000
    assert_eq!(dec.u64().unwrap(), 1_000_000_000);
    let inner_len = dec.map().unwrap().unwrap();
    assert_eq!(inner_len, 2, "expected 2 pool rewards for first entry");
    assert_eq!(dec.bytes().unwrap(), &[0xAA; 28]);
    assert_eq!(dec.u64().unwrap(), 50_000);
    assert_eq!(dec.bytes().unwrap(), &[0xBB; 28]);
    assert_eq!(dec.u64().unwrap(), 75_000);

    // Entry 2: stake=5_000_000_000
    assert_eq!(dec.u64().unwrap(), 5_000_000_000);
    let inner_len2 = dec.map().unwrap().unwrap();
    assert_eq!(inner_len2, 1);
    assert_eq!(dec.bytes().unwrap(), &[0xCC; 28]);
    assert_eq!(dec.u64().unwrap(), 250_000);
}

// ===========================================================================
// Test 2: GetStakeDistribution (tag 7)
// ===========================================================================

fn make_stake_distribution() -> QueryResult {
    QueryResult::StakeDistribution(vec![
        StakePoolSnapshot {
            pool_id: vec![0x11; 28],
            stake: 300_000_000,
            vrf_keyhash: vec![0x22; 32],
            total_active_stake: 1_000_000_000,
        },
        StakePoolSnapshot {
            pool_id: vec![0x33; 28],
            stake: 700_000_000,
            vrf_keyhash: vec![0x44; 32],
            total_active_stake: 1_000_000_000,
        },
    ])
}

#[test]
fn test_stake_distribution_fixture() {
    let result = make_stake_distribution();
    let encoded = encode_query_result(&result);
    assert_fixture("Result_Conway_StakeDistribution", &encoded);
}

#[test]
fn test_stake_distribution_structure() {
    let result = make_stake_distribution();
    let encoded = encode_query_result(&result);
    let payload = strip_msg_and_hfc(&encoded);
    let mut dec = decoder(payload);

    // Map<pool_hash(28), IndividualPoolStake>
    let map_len = dec.map().unwrap().unwrap();
    assert_eq!(map_len, 2);

    // Pool 1
    assert_eq!(dec.bytes().unwrap(), &[0x11; 28]);
    let arr = dec.array().unwrap().unwrap();
    assert_eq!(arr, 2, "IndividualPoolStake = array(2)");
    // tag(30) rational
    let tag = dec.tag().unwrap();
    assert_eq!(tag.as_u64(), 30, "expected tag(30) for rational");
    let rat_arr = dec.array().unwrap().unwrap();
    assert_eq!(rat_arr, 2);
    let num = dec.u64().unwrap();
    let den = dec.u64().unwrap();
    assert_eq!(num, 300_000_000);
    assert_eq!(den, 1_000_000_000);
    // VRF keyhash
    assert_eq!(dec.bytes().unwrap(), &[0x22; 32]);

    // Pool 2
    assert_eq!(dec.bytes().unwrap(), &[0x33; 28]);
    let arr2 = dec.array().unwrap().unwrap();
    assert_eq!(arr2, 2);
    dec.skip().unwrap(); // skip rational
    assert_eq!(dec.bytes().unwrap(), &[0x44; 32]);
}

