// Test 3: GetRewardInfoPools (tag 18)
// ===========================================================================

fn make_reward_info_pools() -> QueryResult {
    QueryResult::RewardInfoPools(vec![PoolRewardInfo {
        pool_id: vec![0xAB; 28],
        stake: 500_000_000_000,
        owner_stake: 50_000_000_000,
        pool_reward: 1_000_000,
        leader_reward: 400_000,
        member_reward: 600_000,
        margin: (3, 100),
        cost: 340_000_000,
    }])
}

#[test]
fn test_reward_info_pools_fixture() {
    let result = make_reward_info_pools();
    let encoded = encode_query_result(&result);
    assert_fixture("Result_Conway_RewardInfoPools", &encoded);
}

#[test]
fn test_reward_info_pools_structure() {
    let result = make_reward_info_pools();
    let encoded = encode_query_result(&result);
    let payload = strip_msg_and_hfc(&encoded);
    let mut dec = decoder(payload);

    // Map<pool_hash, PoolRewardInfo>
    let map_len = dec.map().unwrap().unwrap();
    assert_eq!(map_len, 1);

    assert_eq!(dec.bytes().unwrap(), &[0xAB; 28]);
    let arr = dec.array().unwrap().unwrap();
    assert_eq!(arr, 7, "PoolRewardInfo = array(7)");

    assert_eq!(dec.u64().unwrap(), 500_000_000_000, "stake");
    assert_eq!(dec.u64().unwrap(), 50_000_000_000, "owner_stake");
    assert_eq!(dec.u64().unwrap(), 1_000_000, "pool_reward");
    assert_eq!(dec.u64().unwrap(), 400_000, "leader_reward");
    assert_eq!(dec.u64().unwrap(), 600_000, "member_reward");

    // Margin: tag(30)[3, 100]
    let tag = dec.tag().unwrap();
    assert_eq!(tag.as_u64(), 30);
    let rat_arr = dec.array().unwrap().unwrap();
    assert_eq!(rat_arr, 2);
    assert_eq!(dec.u64().unwrap(), 3);
    assert_eq!(dec.u64().unwrap(), 100);

    assert_eq!(dec.u64().unwrap(), 340_000_000, "cost");
}

