// Test 4: GetPoolState (tag 19)
// ===========================================================================

fn make_pool_state() -> QueryResult {
    let pool_params = PoolParamsSnapshot {
        pool_id: vec![0xDE; 28],
        vrf_keyhash: vec![0xEF; 32],
        pledge: 1_000_000_000,
        cost: 340_000_000,
        margin_num: 1,
        margin_den: 100,
        reward_account: vec![0xE0; 29],
        owners: vec![vec![0xA1; 28]],
        relays: vec![RelaySnapshot::SingleHostName {
            port: Some(3001),
            dns_name: "relay1.example.com".to_string(),
        }],
        metadata_url: Some("https://example.com/pool.json".to_string()),
        metadata_hash: Some(vec![0xBE; 32]),
    };

    QueryResult::PoolState {
        pool_params: vec![pool_params],
        future_pool_params: vec![],
        retiring: vec![(vec![0xCC; 28], 500)],
        deposits: vec![(vec![0xDE; 28], 500_000_000)],
    }
}

#[test]
fn test_pool_state_fixture() {
    let result = make_pool_state();
    let encoded = encode_query_result(&result);
    assert_fixture("Result_Conway_PoolState", &encoded);
}

#[test]
fn test_pool_state_structure() {
    let result = make_pool_state();
    let encoded = encode_query_result(&result);
    let payload = strip_msg_and_hfc(&encoded);
    let mut dec = decoder(payload);

    // QueryPoolStateResult: array(4)
    let arr = dec.array().unwrap().unwrap();
    assert_eq!(arr, 4, "PoolState = array(4)");

    // [0] pool_params map (1 entry)
    let map0 = dec.map().unwrap().unwrap();
    assert_eq!(map0, 1);
    assert_eq!(dec.bytes().unwrap(), &[0xDE; 28]); // pool_id key
                                                   // PoolParams is an array — just skip it for structural check
    dec.skip().unwrap();

    // [1] future_pool_params map (0 entries)
    let map1 = dec.map().unwrap().unwrap();
    assert_eq!(map1, 0);

    // [2] retiring map (1 entry)
    let map2 = dec.map().unwrap().unwrap();
    assert_eq!(map2, 1);
    assert_eq!(dec.bytes().unwrap(), &[0xCC; 28]);
    assert_eq!(dec.u64().unwrap(), 500);

    // [3] deposits map (1 entry)
    let map3 = dec.map().unwrap().unwrap();
    assert_eq!(map3, 1);
    assert_eq!(dec.bytes().unwrap(), &[0xDE; 28]);
    assert_eq!(dec.u64().unwrap(), 500_000_000);
}

